<?php require_once __DIR__.'/includes/functions.php';if($_SERVER['REQUEST_METHOD']==='POST'){check_csrf();$ref=make_ref('FHBF-SP');db()->prepare("INSERT INTO sponsor_enquiries(reference,organisation,contact_person,email,phone,sponsorship_level,notes,status) VALUES(?,?,?,?,?,?,?,'New Lead')")->execute([$ref,$_POST['organisation'],$_POST['contact_person'],$_POST['email'],$_POST['phone'],$_POST['sponsorship_level'],$_POST['notes']??'']);flash('success',"Sponsor enquiry received. Reference: $ref");redirect('/sponsors.php');}include __DIR__.'/includes/header.php';?><section class="section"><h1>Sponsors</h1><div class="grid"><?php foreach(db()->query("SELECT * FROM sponsor_packages WHERE active=1 ORDER BY sort_order,id")->fetchAll() as $p): ?><div class="card"><h3><?=h($p['name'])?></h3><div class="price">US$<?=h($p['price'])?>+</div><p><?=h($p['benefits'])?></p></div><?php endforeach; ?></div><form class="card form" method="post"><input type="hidden" name="csrf" value="<?=csrf_token()?>"><label>Organisation<input name="organisation" required></label><label>Contact Person<input name="contact_person" required></label><label>Email<input name="email"></label><label>Phone<input name="phone"></label><label>Level<input name="sponsorship_level"></label><label>Notes<textarea name="notes"></textarea></label><button>Submit</button></form></section><?php include __DIR__.'/includes/footer.php'; ?>